@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_5f610d104ad3471081daf49f15c32159.Services
@using Microsoft.AspNetCore.WebUtilities
@inject IRecipeService RecipeService
@inject NavigationManager Navigation
@inject ILogger<Recipes> Logger
@implements IDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes for Cuisine @CuisineId</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <ul>
        @foreach (var recipe in DisplayedRecipes)
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <span class="text-muted">(@recipe.PrepTimeMinutes min)</span>
            </li>
        }
    </ul>
}

@code {
    [Parameter] public int CuisineId { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private string? _sort;

    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> DisplayedRecipes
    {
        get
        {
            if (_recipes is null) return Enumerable.Empty<Recipe>();
            return _sort == "popular"
                ? _recipes.OrderBy(r => r.PrepTimeMinutes)
                : _recipes.OrderByDescending(r => r.Id);
        }
    }

    protected override void OnInitialized()
    {
        Navigation.LocationChanged += OnLocationChanged;
    }

    protected override async Task OnParametersSetAsync()
    {
        ParseSort();

        if (CuisineId != _loadedCuisineId)
        {
            await LoadRecipesAsync();
        }
    }

    private void OnLocationChanged(object? sender, Microsoft.AspNetCore.Components.Routing.LocationChangedEventArgs e)
    {
        var previousSort = _sort;
        ParseSort();

        if (_sort != previousSort && _recipes is not null)
        {
            InvokeAsync(StateHasChanged);
        }
    }

    private void ParseSort()
    {
        var uri = new Uri(Navigation.Uri);
        var query = QueryHelpers.ParseQuery(uri.Query);
        _sort = query.TryGetValue("sort", out var sortValue) ? sortValue.ToString() : null;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _error = null;
        _isRefreshing = _recipes is not null;

        var cuisineId = CuisineId;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(cuisineId, token);

            // Don't apply results if cancelled during await
            if (token.IsCancellationRequested) return;

            _recipes = result;
            _loadedCuisineId = cuisineId;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Request was intentionally cancelled; nothing to do.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", cuisineId);
            _error = "The request timed out. Please try again.";
            _recipes = null;
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", cuisineId);
            _error = "Something went wrong loading recipes. Please try again.";
            _recipes = null;
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    public void Dispose()
    {
        Navigation.LocationChanged -= OnLocationChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

